/* Minimal QR Code generator for short byte-mode labels (QR v1-L). Exposes window.QRCode.toCanvas(el,text). */
(function(g){function gfMul(x,y){var r=0;while(y){if(y&1)r^=x;x<<=1;if(x&256)x^=285;y>>=1}return r}function ecc(data){var gen=[87,229,146,149,238,102,21],res=[0,0,0,0,0,0,0];for(var i=0;i<data.length;i++){var f=data[i]^res.shift();res.push(0);for(var j=0;j<7;j++)res[j]^=gfMul(gen[j],f)}return res}function bits(v,n,a){for(var i=n-1;i>=0;i--)a.push((v>>>i)&1)}function makeBytes(text){var enc=new TextEncoder().encode(text),b=[];bits(4,4,b);bits(enc.length,8,b);for(var i=0;i<enc.length;i++)bits(enc[i],8,b);var max=152;for(i=0;i<4&&b.length<max;i++)b.push(0);while(b.length%8)b.push(0);var out=[];for(i=0;i<b.length;i+=8)out.push(parseInt(b.slice(i,i+8).join(""),2));for(i=0;out.length<19;i++)out.push(i%2?17:236);return out.concat(ecc(out))}function drawFinder(m,r,c,res){for(var y=-1;y<=7;y++)for(var x=-1;x<=7;x++){var rr=r+y,cc=c+x;if(rr<0||cc<0||rr>=21||cc>=21)continue;var v=(x>=0&&x<=6&&y>=0&&y<=6&&(x==0||x==6||y==0||y==6||(x>=2&&x<=4&&y>=2&&y<=4)));m[rr][cc]=v?1:0;res[rr][cc]=1}}function makeMatrix(text){var m=Array.from({length:21},()=>Array(21).fill(0)),res=Array.from({length:21},()=>Array(21).fill(0));drawFinder(m,0,0,res);drawFinder(m,0,14,res);drawFinder(m,14,0,res);for(var i=8;i<13;i++){m[6][i]=i%2?0:1;res[6][i]=1;m[i][6]=i%2?0:1;res[i][6]=1}m[13][8]=1;res[13][8]=1;var fmt=0x77c4,pos=[[8,0],[8,1],[8,2],[8,3],[8,4],[8,5],[8,7],[8,8],[7,8],[5,8],[4,8],[3,8],[2,8],[1,8],[0,8]],pos2=[[20,8],[19,8],[18,8],[17,8],[16,8],[15,8],[14,8],[8,20],[8,19],[8,18],[8,17],[8,16],[8,15],[8,14],[8,13]];for(i=0;i<15;i++){var bit=(fmt>>i)&1,p=pos[i],q=pos2[i];m[p[0]][p[1]]=bit;res[p[0]][p[1]]=1;m[q[0]][q[1]]=bit;res[q[0]][q[1]]=1}var data=[];makeBytes(text).forEach(function(c){bits(c,8,data)});var dir=-1,row=20,idx=0;for(var col=20;col>0;col-=2){if(col==6)col--;while(true){for(var dx=0;dx<2;dx++){var cc=col-dx;if(!res[row][cc]){var val=data[idx++]||0;if((row+cc)%2==0)val^=1;m[row][cc]=val}}row+=dir;if(row<0||row>=21){row-=dir;dir=-dir;break}}}return m}function render(el,text,opt){opt=opt||{};var scale=opt.scale||5,pad=opt.margin||4,m=makeMatrix(String(text||"")),size=(21+pad*2)*scale,canvas=el&&el.tagName==="CANVAS"?el:document.createElement("canvas");canvas.width=size;canvas.height=size;var ctx=canvas.getContext("2d");ctx.fillStyle="#fff";ctx.fillRect(0,0,size,size);ctx.fillStyle="#000";for(var r=0;r<21;r++)for(var c=0;c<21;c++)if(m[r][c])ctx.fillRect((c+pad)*scale,(r+pad)*scale,scale,scale);if(el&&el!==canvas){el.innerHTML="";el.appendChild(canvas)}return canvas}g.QRCode={toCanvas:function(el,text,opt){return render(el,text,opt)},toDataURL:function(text,opt){return render(null,text,opt).toDataURL("image/png")}}})(window);
